mapper.select:
SELECT 
FROM im_user_session
WHERE user_id = #{userId}
  AND conversation_id = #{conversationId}
  AND is_deleted = 0

mapper.update:
UPDATE im_user_session
SET unread_count = #{unreadCount},
    update_time = NOW()
WHERE user_id = #{userId}
  AND conversation_id = #{conversationId}

UPDATE im_user_session
SET last_read_message_id = #{lastReadMessageId},
    update_time = NOW()
WHERE user_id = #{userId}
  AND conversation_id = #{conversationId}

UPDATE im_user_session
SET is_pinned = #{isPinned},
    pinned_time = CASE WHEN #{isPinned} = 1 THEN NOW() ELSE NULL END,
    update_time = NOW()
WHERE user_id = #{userId}
  AND conversation_id = #{conversationId}

UPDATE im_user_session
SET is_muted = #{isMuted},
    update_time = NOW()
WHERE user_id = #{userId}
  AND conversation_id = #{conversationId}

UPDATE im_user_session
SET is_archived = #{isArchived},
    update_time = NOW()
WHERE user_id = #{userId}
  AND conversation_id = #{conversationId}

UPDATE im_user_session
SET draft_content = #{draftContent},
    draft_time = CASE WHEN #{draftContent} IS NULL OR #{draftContent} = '' THEN NULL ELSE NOW() END,
    update_time = NOW()
WHERE user_id = #{userId}
  AND conversation_id = #{conversationId}

UPDATE im_user_session
SET is_deleted = 1,
    deleted_time = NOW(),
    update_time = NOW()
WHERE user_id = #{userId}
  AND conversation_id = #{conversationId}
